mapper.select:
SELECT * FROM ( SELECT inner_q.*, ROWNUM AS rn FROM ( SELECT user_code AS userCode, login_id AS loginId, user_name AS userName, email AS email, status AS status, owner_yn AS ownerYn, admin_yn AS adminYn, CASE WHEN owner_yn = 1 THEN '최고관리자' WHEN NVL(admin_yn, 0) = 1 THEN '관리자' ELSE '일반 사용자' END AS roleName FROM users WHERE company_id = #{companyId} AND status IN ('a2', 'a3')
AND (LOWER(login_id) LIKE '%' || LOWER(#{keyword}) || '%' OR LOWER(user_name) LIKE '%' || LOWER(#{keyword}) || '%')
ORDER BY NVL(owner_yn, 0) DESC, NVL(admin_yn, 0) DESC, CASE status WHEN 'a2' THEN 0 ELSE 1 END, login_id ASC ) inner_q WHERE ROWNUM <= #{offset} + #{pageSize} ) WHERE rn > #{offset}

mapper.update:
UPDATE users
SET status = #{status}
WHERE company_id = #{companyId}
  AND user_code = #{userCode}
  AND status IN ('a2', 'a3')
  AND NVL(owner_yn, 0) = 0
  AND (#{actorOwnerYn} = 1 OR NVL(admin_yn, 0) = 0)

